import{_ as a,o as r,c as i,ah as o}from"./chunks/framework.ojwJKwrc.js";const p=JSON.parse('{"title":"Triage","description":"","frontmatter":{},"headers":[],"relativePath":"internals/triage.md","filePath":"internals/triage.md"}'),t={name:"internals/triage.md"};function l(s,e,n,c,u,h){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="triage" tabindex="-1">Triage <a class="header-anchor" href="#triage" aria-label="Permalink to &quot;Triage&quot;">​</a></h1><p>This page defines the lightweight maintainer workflow for prioritizing GitHub work in <code>celox</code>.</p><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Keep the queue small, visible, and biased toward:</p><ol><li>correctness of simulator behavior</li><li>user-facing usability regressions</li><li>mergeable work already in flight</li></ol><p>GitHub Projects can still be used as a view layer, but the source of truth should remain:</p><ul><li>Issues for work items</li><li>Pull requests for implementation</li><li>Tracking issues for multi-step themes</li></ul><h2 id="queue-buckets" tabindex="-1">Queue Buckets <a class="header-anchor" href="#queue-buckets" aria-label="Permalink to &quot;Queue Buckets&quot;">​</a></h2><p>Every open issue and PR should fit one of these buckets.</p><h3 id="now" tabindex="-1">Now <a class="header-anchor" href="#now" aria-label="Permalink to &quot;Now&quot;">​</a></h3><p>Work that should be reviewed, merged, or fixed before taking on new feature work.</p><p>Typical criteria:</p><ul><li>open PR that is already testable and close to merge</li><li>bug that breaks CI, docs, playground, or common workflows</li><li>semantic bug that can produce incorrect simulation results</li></ul><h3 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h3><p>Important follow-up work that should start after <code>Now</code> is cleared.</p><p>Typical criteria:</p><ul><li>core feature gaps with direct user impact</li><li>support gaps already split into concrete issues</li><li>diagnostics improvements around common failure cases</li></ul><h3 id="later" tabindex="-1">Later <a class="header-anchor" href="#later" aria-label="Permalink to &quot;Later&quot;">​</a></h3><p>Useful work that is real but not on the immediate path.</p><p>Typical criteria:</p><ul><li>dependency maintenance</li><li>future backend expansion</li><li>cleanup that depends on upstream release timing</li></ul><h3 id="tracking" tabindex="-1">Tracking <a class="header-anchor" href="#tracking" aria-label="Permalink to &quot;Tracking&quot;">​</a></h3><p>Umbrella issues that organize a theme but should not compete directly with execution issues.</p><p>Typical criteria:</p><ul><li>parent issue for a family of sub-issues</li><li>inventory / classification issue</li><li>roadmap marker spanning several PRs</li></ul><h2 id="priority-rules" tabindex="-1">Priority Rules <a class="header-anchor" href="#priority-rules" aria-label="Permalink to &quot;Priority Rules&quot;">​</a></h2><p>Use these precedence rules when two tasks compete.</p><ol><li>Merge or unblock high-signal open PRs before opening fresh work.</li><li>Prefer correctness over optimization unless a proven perf regression is blocking a release.</li><li>Prefer user-visible breakage over internal cleanup.</li><li>Prefer concrete child issues over broad tracking issues.</li><li>Keep upstream-waiting tasks out of the active queue unless the external blocker moved.</li></ol><h2 id="recommended-fields" tabindex="-1">Recommended Fields <a class="header-anchor" href="#recommended-fields" aria-label="Permalink to &quot;Recommended Fields&quot;">​</a></h2><p>If a GitHub Project is used, keep the schema minimal:</p><ul><li><code>Bucket</code>: <code>Now</code>, <code>Next</code>, <code>Later</code>, <code>Tracking</code></li><li><code>Area</code>: <code>sim-core</code>, <code>backend-native</code>, <code>ts-runtime</code>, <code>playground</code>, <code>ci/docs</code>, <code>upstream-veryl</code></li><li><code>Kind</code>: <code>bug</code>, <code>feature</code>, <code>tracking</code>, <code>debt</code>, <code>dependency</code></li></ul><p>Avoid duplicating the same meaning in both labels and project fields.</p><h2 id="_2026-04-27-snapshot" tabindex="-1">2026-04-27 Snapshot <a class="header-anchor" href="#_2026-04-27-snapshot" aria-label="Permalink to &quot;2026-04-27 Snapshot&quot;">​</a></h2><p>This snapshot reflects the open GitHub queue inspected on April 27, 2026.</p><h3 id="now-1" tabindex="-1">Now <a class="header-anchor" href="#now-1" aria-label="Permalink to &quot;Now&quot;">​</a></h3><ul><li>PR <a href="https://github.com/celox-sim/celox/pull/79" target="_blank" rel="noreferrer">#79</a>: playground 4-state virtual module port typing fix</li><li>PR <a href="https://github.com/celox-sim/celox/pull/78" target="_blank" rel="noreferrer">#78</a>: align loop variables with Veryl <code>i32</code> semantics</li></ul><h3 id="next-1" tabindex="-1">Next <a class="header-anchor" href="#next-1" aria-label="Permalink to &quot;Next&quot;">​</a></h3><ul><li>Issue <a href="https://github.com/celox-sim/celox/issues/54" target="_blank" rel="noreferrer">#54</a>: playground 4-state typing regression This should close with PR #79, so it stays effectively in <code>Now</code> until merged.</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/44" target="_blank" rel="noreferrer">#44</a>: array literal lowering gaps</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/45" target="_blank" rel="noreferrer">#45</a>: expression lowering gaps</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/33" target="_blank" rel="noreferrer">#33</a>: report true loop location</li></ul><h3 id="later-1" tabindex="-1">Later <a class="header-anchor" href="#later-1" aria-label="Permalink to &quot;Later&quot;">​</a></h3><ul><li>Issue <a href="https://github.com/celox-sim/celox/issues/42" target="_blank" rel="noreferrer">#42</a>: const function evaluation in module params The current <code>std_mux</code> / <code>std_demux</code> smoke tests pass on Celox backends, so this issue likely needs closure or scope correction rather than new implementation work.</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/72" target="_blank" rel="noreferrer">#72</a>: remove <code>deps/veryl</code> submodule once <code>veryl</code> <code>0.20.0</code> is available</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/36" target="_blank" rel="noreferrer">#36</a>: dependency dashboard</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/16" target="_blank" rel="noreferrer">#16</a>: instance-contiguous <code>MemoryLayout</code></li><li>Issue <a href="https://github.com/celox-sim/celox/issues/30" target="_blank" rel="noreferrer">#30</a>: native testbench DSE</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/25" target="_blank" rel="noreferrer">#25</a>: support Veryl native testbench</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/26" target="_blank" rel="noreferrer">#26</a>: native ARM backend</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/27" target="_blank" rel="noreferrer">#27</a>: native RISC-V backend</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/24" target="_blank" rel="noreferrer">#24</a>: improve generic-argument error message</li></ul><h3 id="tracking-1" tabindex="-1">Tracking <a class="header-anchor" href="#tracking-1" aria-label="Permalink to &quot;Tracking&quot;">​</a></h3><ul><li>Issue <a href="https://github.com/celox-sim/celox/issues/41" target="_blank" rel="noreferrer">#41</a>: simulator support gaps by category</li><li>Issue <a href="https://github.com/celox-sim/celox/issues/43" target="_blank" rel="noreferrer">#43</a>: function-call lowering support</li><li>Issues <a href="https://github.com/celox-sim/celox/issues/57" target="_blank" rel="noreferrer">#57</a>, <a href="https://github.com/celox-sim/celox/issues/58" target="_blank" rel="noreferrer">#58</a>, <a href="https://github.com/celox-sim/celox/issues/59" target="_blank" rel="noreferrer">#59</a>, <a href="https://github.com/celox-sim/celox/issues/60" target="_blank" rel="noreferrer">#60</a>, <a href="https://github.com/celox-sim/celox/issues/61" target="_blank" rel="noreferrer">#61</a>, <a href="https://github.com/celox-sim/celox/issues/62" target="_blank" rel="noreferrer">#62</a>, <a href="https://github.com/celox-sim/celox/issues/63" target="_blank" rel="noreferrer">#63</a>: concrete child issues under the broader function-call support theme</li></ul><h2 id="operating-cadence" tabindex="-1">Operating Cadence <a class="header-anchor" href="#operating-cadence" aria-label="Permalink to &quot;Operating Cadence&quot;">​</a></h2><p>Run this review whenever a PR merges or a new user-visible bug appears.</p><ol><li>Re-evaluate all open PRs and move mergeable ones into <code>Now</code>.</li><li>Remove closed issues from the bucket list.</li><li>Promote only one or two <code>Next</code> items at a time.</li><li>Leave broad roadmap or upstream-waiting tasks in <code>Later</code> or <code>Tracking</code>.</li></ol><h2 id="should-this-be-a-skill" tabindex="-1">Should This Be A Skill? <a class="header-anchor" href="#should-this-be-a-skill" aria-label="Permalink to &quot;Should This Be A Skill?&quot;">​</a></h2><p>Usually not at first.</p><p>For this repository, the stable asset should be this document because:</p><ul><li>the queue is repo-specific</li><li>issue numbers and priorities change over time</li><li>maintainers need a visible policy in the repo itself</li></ul><p>A skill becomes useful when the workflow is reused across repositories, for example:</p><ul><li>a personal weekly GitHub triage routine</li><li>a standard way to classify PRs and issues across several projects</li><li>a repeatable sequence of GitHub connector actions with consistent output</li></ul><p>Good split:</p><ul><li>repo-specific policy: docs page in this repository</li><li>reusable personal workflow: skill</li></ul>',53)])])}const m=a(t,[["render",l]]);export{p as __pageData,m as default};
